+++ b/absl/strings/cord.cc
@@ -1013,7 +1013,7 @@ inline int SharedCompareImpl(const Cord& lhs, const RHS& rhs) {
   return data_comp_res == 0 ? +1 : data_comp_res;
 }

-int Cord::Compare(absl::string_view rhs) const {
+int Cord::CompareImpl(absl::string_view rhs) const {
   return SharedCompareImpl(*this, rhs);
 }

diff --git a/absl/strings/cord.h b/absl/strings/cord.h
index 3278296..bff6a3a 100644
--- a/absl/strings/cord.h
+++ b/absl/strings/cord.h
@@ -1057,6 +1057,7 @@ class Cord {
   bool EqualsImpl(absl::string_view rhs, size_t size_to_compare) const;
   bool EqualsImpl(const Cord& rhs, size_t size_to_compare) const;
   int CompareImpl(const Cord& rhs) const;
+  int CompareImpl(absl::string_view rhs) const;

   template <typename ResultType, typename RHS>
   friend ResultType GenericCompare(const Cord& lhs, const RHS& rhs,
@@ -1479,6 +1480,21 @@ inline int Cord::Compare(const Cord& rhs) const {
   return CompareImpl(rhs);
 }

+inline int Cord::Compare(absl::string_view rhs) const {
+  if (!contents_.is_tree()) {
+    const char* data = contents_.data_.as_chars();
+    size_t lhs_size = contents_.data_.inline_size();
+    size_t rhs_size = rhs.size();
+    size_t common = std::min(lhs_size, rhs_size);
+    int r = common > 0 ? ::memcmp(data, rhs.data(), common) : 0;
+    if (r != 0) return r < 0 ? -1 : 1;
+    if (lhs_size == rhs_size) return 0;
+    return lhs_size < rhs_size ? -1 : 1;
+  }
+
+  return CompareImpl(rhs);
+}
+
